library(scBubbletree)
library(ggplot2)
library(patchwork)
library(dplyr)
library(boot)


get_hdi <- function(vec, hdi_level) {
  sortedPts <- sort(vec)
  ciIdxInc <- floor(hdi_level * length(sortedPts))
  nCIs = length(sortedPts) - ciIdxInc
  ciWidth = rep(0 , nCIs)
  for (i in 1:nCIs) {
    ciWidth[i] = sortedPts[i + ciIdxInc] - sortedPts[i]
  }
  HDImin = sortedPts[which.min(ciWidth)]
  HDImax = sortedPts[which.min(ciWidth) + ciIdxInc]
  HDIlim = c(HDImin, HDImax)
  return(HDIlim)
}


# data generated by gex_analysis.R
btd_input <- get(load("data/GEX/processed/btd_input.RData"))
d <- get(load("data/GEX/processed/d_final.RData"))
btd <- get(load("data/GEX/processed/btd.RData"))


A <- btd_input$A
m <- btd_input$m
e <- btd_input$e
symbols <- btd_input$symbols


gcd <- get(load(file = "res/gcd.RData"))
ns <- gcd$node_summary
ns$sample <- gsub(pattern = "EBV", replacement = 'E', x = ns$sample)
ns$sample <- gsub(pattern = "MART1", replacement = 'M', x = ns$sample)


ps <- get(load(file = "res/ps.RData"))
bs <- ps$beta
bs <- bs[order(bs$mean, decreasing = T),]
bs$sample <- gsub(pattern = "EBV", replacement = 'E', x = bs$sample)
bs$sample <- gsub(pattern = "MART1", replacement = 'M', x = bs$sample)

# add beta-mean and community to each clone
ns <- merge(x = ns, y = bs[, c("mean", "sample", "community")], 
            by = c("sample", "community"), all.x = TRUE)

nsa <- aggregate(mean~clonotype_id+sample+community, 
                 data = ns, FUN = unique)

# add activation markers
e_as <- e[,colnames(e) %in% symbols$t_act_szabo]
e_as <- data.frame(e_as)
e_as$sample <- d@meta.data$sample
e_as$clonotype_id <- d@meta.data$clonotype_id

e_as <- merge(x = e_as, 
           y = nsa[,c("clonotype_id",  "sample", "community", "mean")], 
           by = c("clonotype_id", "sample"), all.x = TRUE)

e_as$GEX <- apply(X = e_as[, which(colnames(e_as) %in% symbols$t_act_szabo)], 
                  MARGIN = 1, FUN = sum)

cns <- e_as %>%
  group_by(sample, community) %>%
  summarise(mean_Act = mean(GEX, na.rm = TRUE),
            mean_beta = mean(mean, na.rm = TRUE))

fig_2f <- ggplot(data = cns)+
  facet_wrap(~sample, nrow = 1, dir = "h")+
  geom_point(aes(x = mean_beta, y = mean_Act), size = 0.5, 
             shape = 21, fill = "black", col = "white", alpha = 0.7, 
             stroke = 0.1)+
  geom_density_2d(aes(x = mean_beta, y = mean_Act), size = 0.2, 
             col = "orange")+
  theme_bw(base_size = 10)+
  ylab(label = "")+
  xlab(label = "")+ 
  theme(strip.text.x = element_text(margin = margin(0.02,0,0.02,0, "cm")))
fig_2f

ggsave(plot = fig_2f,
       filename = "manuscript/Fig_2_F.pdf",
       device = "pdf",
       width = 4.2,
       height = 1.6)



hdi_level <- 0.95
o <- c()
beta_seq <- seq(from = -1, to = 6, by = 0.5)
for(b in beta_seq) {
  for(s in unique(e_as$sample)) {
    y <- e_as[e_as$sample == s & e_as$mean >= (b-1) & e_as$mean <= (b+1),]
    if(nrow(y)==0) {
      u <- data.frame(M = NA, L95 = NA, H95 = NA)
    } else {
      u <- boot(y[, "GEX", drop = FALSE], statistic=function(data, i){
                  d <- data[i, ]; return(mean(d))}, R=1000)
      hdi <- get_hdi(vec = u$t[,1], hdi_level = hdi_level)
      u <- data.frame(M = mean(u$t[,1]), L95 = hdi[1], H95 = hdi[2])
    }
    o <- rbind(o, data.frame(beta = b, 
                             mean_gex = mean(y$GEX), 
                             var_gex = var(y$GEX), 
                             boot_gex_M = u$M,
                             boot_gex_L95 = u$L95,
                             boot_gex_H95 = u$H95,
                             n = nrow(y),
                             sample = s))
  }
}
rm(b, beta_seq, y, s, u, hdi_level, hdi)



fig_2g <- ggplot(data = o)+
  geom_point(aes(x = beta, y = boot_gex_M, col = sample), shape = 21, size = 0.5)+
  geom_errorbar(aes(x = beta, ymin = boot_gex_L95, ymax = boot_gex_H95, 
                    col = sample), width = 0.05, size = 0.5)+
  geom_line(aes(x = beta, y = boot_gex_M, col = sample), size = 0.5)+
  theme_bw(base_size = 10)+
  theme(legend.position = "top")+
  xlab(label = expression(beta))+
  ylab(label = "T-cell activation")+
  scale_color_manual(name = "",
                     values = c("#fc92a6", "#f72d52", "#91132a", "steelblue", "purple"))


ggsave(plot = fig_2g,
       filename = "manuscript/Fig_2_G.pdf",
       device = "pdf",
       width = 1.5,
       height = 2)
